class Solution:
    def findKthBit(self, n, k):
        """
        :type n: int
        :type k: int
        :rtype: str
        """
        # For small n, we can build the string recursively
        # S_n has length 2^n - 1
        # S_n = S_(n-1) + "1" + invert(reverse(S_(n-1)))

        def get_bit(n, k):
            # Base case
            if n == 1:
                return "0"

            length = (1 << n) - 1  # 2^n - 1
            mid = (length + 1) // 2  # Middle position

            if k < mid:
                # In left part: S_(n-1)
                return get_bit(n - 1, k)
            elif k == mid:
                # Middle bit
                return "1"
            else:
                # In right part: invert(reverse(S_(n-1)))
                # Position from right of S_(n-1)
                pos_from_end = length - k + 1
                bit = get_bit(n - 1, pos_from_end)
                # Invert the bit
                return "1" if bit == "0" else "0"

        return get_bit(n, k)
